function createEmptyGrid() {
	return Array.from({ length: SUDOKU_SIZE }, () => Array(SUDOKU_SIZE).fill(0));
}

function cloneGrid(grid) {
	return grid.map(row => [...row]);
}

let currentGame = null;
let writeUserGrid = () => {};

function resetGame(board) {
	currentGame = createGame({ sudoku: createSudoku(board) });
	setExploreActive(false);
	clearExploreFailure();
	writeUserGrid(currentGame.getSudoku().getGrid());
}

function updateExploreFailure() {
	if (!currentGame || !currentGame.isExploring()) return;

	const failure = currentGame.consumeExploreFailure();
	if (failure) setExploreFailure(failure);
}

function applyMove(pos, value) {
	if (!currentGame) return;

	try {
		currentGame.guess(pos.y, pos.x, value);
		writeUserGrid(currentGame.getSudoku().getGrid());
		updateExploreFailure();
	} catch (error) {
		return false;
	}

	return true;
}

function undoMove() {
	if (!currentGame || !currentGame.canUndo()) return;

	currentGame.undo();
	writeUserGrid(currentGame.getSudoku().getGrid());
}

function redoMove() {
	if (!currentGame || !currentGame.canRedo()) return;

	currentGame.redo();
	writeUserGrid(currentGame.getSudoku().getGrid());
}

function canUndoMove() {
	return Boolean(currentGame && currentGame.canUndo());
}

function canRedoMove() {
	return Boolean(currentGame && currentGame.canRedo());
}

function getCandidateHint(pos) {
	if (!currentGame) return null;

	const candidates = currentGame.getCandidateHint(pos.y, pos.x);
	if (!candidates || candidates.length === 0) return null;

	hints.useHint();
	return candidates;
}

function applyNextHint() {
	if (!currentGame) return null;

	const hint = currentGame.getNextStepHint();
	if (!hint) return null;

	hints.useHint();
	applyMove({ x: hint.col, y: hint.row }, hint.value);
	return hint;
}

function startExplore() {
	if (!currentGame) return false;
	const started = currentGame.startExplore();
	if (started) {
		setExploreActive(true);
		clearExploreFailure();
	}
	return started;
}

function commitExplore() {
	if (!currentGame) return false;
	const committed = currentGame.commitExplore();
	if (committed) {
		setExploreActive(false);
		clearExploreFailure();
		writeUserGrid(currentGame.getSudoku().getGrid());
	}
	return committed;
}

function cancelExplore() {
	if (!currentGame) return false;
	const canceled = currentGame.cancelExplore();
	if (canceled) {
		setExploreActive(false);
		clearExploreFailure();
		writeUserGrid(currentGame.getSudoku().getGrid());
	}
	return canceled;
}

function backtrackExplore() {
	if (!currentGame) return false;
	const backtracked = currentGame.backtrackExplore();
	if (backtracked) {
		clearExploreFailure();
		writeUserGrid(currentGame.getSudoku().getGrid());
	}
	return backtracked;
}

